// The function's ensures is structured as `H ==> det_X_equal(r1, r2, post1_self_, post2_self_)`
// where H is the giant conjunction of run-1 and run-2 post-conditions.
// The previous attempt asserted H-conjuncts directly, which failed because those
// facts are *hypotheses* of an implication ensures, not unconditional ensures.
// Fix: wrap the whole proof in `if H { ... }`. Inside the branch, every H-conjunct
// is in scope, so re-stating triggers and per-key reasoning succeed.

let thread_ptr = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let target_container = pre_self_.get_thread(thread_ptr).owning_container;

if (post1_self_.wf())
    && (post1_self_.page_closure() =~= pre_self_.page_closure())
    && (post1_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post1_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post1_self_.thread_dom() == pre_self_.thread_dom())
    && (forall|p_ptr: ProcPtr|
            #![trigger post1_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                && container_ptr != pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container
                ==> post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                ==> post1_self_.get_container(container_ptr).subtree_set
                    =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                && t_ptr != pre_self_.get_endpoint(endpoint_ptr).queue@[0]
                ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post1_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post1_self_.get_endpoint(e_ptr).owning_container)
    && (post1_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors
        =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors)
    && (post1_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs)
    && (post1_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads)
    && (post1_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children)
    && (post1_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1))
    && (post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads)
    && (post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter)
    && (post1_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state)
    && (post2_self_.wf())
    && (post2_self_.page_closure() =~= pre_self_.page_closure())
    && (post2_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post2_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.thread_dom() == pre_self_.thread_dom())
    && (forall|p_ptr: ProcPtr|
            #![trigger post2_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                && container_ptr != pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container
                ==> post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                ==> post2_self_.get_container(container_ptr).subtree_set
                    =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                && t_ptr != pre_self_.get_endpoint(endpoint_ptr).queue@[0]
                ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post2_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post2_self_.get_endpoint(e_ptr).owning_container)
    && (post2_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors
        =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors)
    && (post2_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs)
    && (post2_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads)
    && (post2_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children)
    && (post2_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1))
    && (post2_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads)
    && (post2_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter)
    && (post2_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state)
{
    // === Domains agree across post1, post2, pre. ===
    assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
    assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
    assert(post1_self_.container_dom() == pre_self_.container_dom());
    assert(post2_self_.container_dom() == pre_self_.container_dom());
    assert(post1_self_.thread_dom() == pre_self_.thread_dom());
    assert(post2_self_.thread_dom() == pre_self_.thread_dom());
    assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
    assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());

    // === process_perms: domain equal; per-key value pinned to pre on both runs. ===
    assert((post1_self_.process_perms)@.dom() =~= (post2_self_.process_perms)@.dom());
    assert forall|p_ptr: ProcPtr|
        #![trigger (post1_self_.process_perms)@[p_ptr], (post2_self_.process_perms)@[p_ptr]]
        (post1_self_.process_perms)@.dom().contains(p_ptr) implies
        (post1_self_.process_perms)@[p_ptr] == (post2_self_.process_perms)@[p_ptr] by {
        assert(pre_self_.proc_dom().contains(p_ptr));
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    }
    assert((post1_self_.process_perms)@ =~= (post2_self_.process_perms)@);

    // === endpoint_perms: domain equal; non-target endpoints pinned to pre,
    //     target endpoint has queue/owning_threads/rf_counter/queue_state/owning_container
    //     all pinned by ensures. ===
    assert((post1_self_.endpoint_perms)@.dom() =~= (post2_self_.endpoint_perms)@.dom());
    assert forall|e_ptr: EndpointPtr|
        #![trigger (post1_self_.endpoint_perms)@[e_ptr], (post2_self_.endpoint_perms)@[e_ptr]]
        (post1_self_.endpoint_perms)@.dom().contains(e_ptr) implies
        (post1_self_.endpoint_perms)@[e_ptr] == (post2_self_.endpoint_perms)@[e_ptr] by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        if e_ptr != endpoint_ptr {
            assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
            assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        }
    }
    assert((post1_self_.endpoint_perms)@ =~= (post2_self_.endpoint_perms)@);

    // === thread_perms: domain equal; non-target threads pinned to pre,
    //     target thread has endpoint_descriptors pinned. ===
    assert((post1_self_.thread_perms)@.dom() =~= (post2_self_.thread_perms)@.dom());
    assert forall|t_ptr: ThreadPtr|
        #![trigger (post1_self_.thread_perms)@[t_ptr], (post2_self_.thread_perms)@[t_ptr]]
        (post1_self_.thread_perms)@.dom().contains(t_ptr) implies
        (post1_self_.thread_perms)@[t_ptr] == (post2_self_.thread_perms)@[t_ptr] by {
        assert(pre_self_.thread_dom().contains(t_ptr));
        if t_ptr != thread_ptr {
            assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
            assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        }
    }
    assert((post1_self_.thread_perms)@ =~= (post2_self_.thread_perms)@);

    // === container_perms: domain equal; non-target containers pinned to pre,
    //     target container has subtree_set/owned_procs/owned_threads/children
    //     pinned. ===
    assert((post1_self_.container_perms)@.dom() =~= (post2_self_.container_perms)@.dom());
    assert forall|c_ptr: ContainerPtr|
        #![trigger (post1_self_.container_perms)@[c_ptr], (post2_self_.container_perms)@[c_ptr]]
        (post1_self_.container_perms)@.dom().contains(c_ptr) implies
        (post1_self_.container_perms)@[c_ptr] == (post2_self_.container_perms)@[c_ptr] by {
        assert(pre_self_.container_dom().contains(c_ptr));
        if c_ptr != target_container {
            assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        }
    }
    assert((post1_self_.container_perms)@ =~= (post2_self_.container_perms)@);

    // Unit results are trivially equal.
    assert(r1 == r2);
}
